using System.Text.RegularExpressions;

namespace VisualRelay.Guards;

/// <summary>
/// Pure classification functions that flag raw color / font-size literals
/// outside the central design-token files (Theme/Colors.axaml,
/// Theme/Typography.axaml).  Each function is stateless — feed it file
/// contents and receive a list of violations.  The real-tree scan is a
/// separate [Fact] in the test project.
/// </summary>
public static class DesignTokenGuard
{
    /// <summary>Describes one raw-literal violation.</summary>
    public sealed record Violation(string Path, int Line, string Text, string Rule);

    /// <summary>
    /// Suffixes of the two files where raw hex literals are allowed to live.
    /// Compared case-insensitively against the end of each file path.
    /// </summary>
    public static readonly IReadOnlySet<string> DefaultTokenFileSuffixes =
        new HashSet<string>(StringComparer.Ordinal)
        {
            "Theme/Colors.axaml",
            "Theme/Typography.axaml",
        };

    /// <summary>Brush-bearing attribute names that rule 3 scans.</summary>
    private static readonly HashSet<string> BrushAttributes =
        new(StringComparer.OrdinalIgnoreCase)
        {
            "Foreground", "Background", "BorderBrush", "Fill", "Stroke",
        };

    // ── Rule 1: no #-hex anywhere in .axaml outside the two token files ──

    private static readonly Regex HexRegex =
        new(@"#[0-9A-Fa-f]{6}([0-9A-Fa-f]{2})?", RegexOptions.Compiled);

    /// <summary>
    /// Returns every line in <paramref name="axamlFiles"/> that contains a
    /// <c>#RGB</c>/<c>#RRGGBB</c>/<c>#AARRGGBB</c> literal, unless the file
    /// path is in <paramref name="allowListedPaths"/>.
    /// </summary>
    public static IReadOnlyList<Violation> FindHexViolations(
        IReadOnlyList<(string Path, string[] Lines)> axamlFiles,
        IReadOnlySet<string>? allowListedPaths = null)
    {
        var allowed = allowListedPaths ?? DefaultTokenFileSuffixes;
        var violations = new List<Violation>();

        foreach (var (path, lines) in axamlFiles)
        {
            if (IsAllowListed(path, allowed))
                continue;

            for (var i = 0; i < lines.Length; i++)
            {
                if (HexRegex.IsMatch(lines[i]))
                {
                    violations.Add(new Violation(path, i + 1, lines[i].Trim(), "hex-color"));
                }
            }
        }

        violations.Sort((a, b) =>
        {
            var pc = string.CompareOrdinal(a.Path, b.Path);
            return pc != 0 ? pc : a.Line.CompareTo(b.Line);
        });
        return violations;
    }

    // ── Rule 2: FontSize must be a resource reference ────────────────────

    // Matches FontSize="<value>" where value does NOT start with { (i.e. is
    // not a markup extension / resource reference).
    private static readonly Regex FontSizeAttrRegex =
        new(@"FontSize\s*=\s*""(?!\{)", RegexOptions.Compiled | RegexOptions.IgnoreCase);

    // Matches <Setter Property="FontSize" Value="<value>"/> where value does
    // NOT start with {.
    private static readonly Regex FontSizeSetterRegex =
        new(@"Property\s*=\s*""FontSize""\s+Value\s*=\s*""(?!\{)", RegexOptions.Compiled | RegexOptions.IgnoreCase);

    /// <summary>
    /// Returns every line where a <c>FontSize</c> attribute or
    /// <c>&lt;Setter Property="FontSize"</c> carries a numeric literal
    /// rather than a <c>{StaticResource …}</c> or
    /// <c>{DynamicResource …}</c> reference.  Raw numbers on other
    /// attributes (Width, Padding, …) are intentionally ignored.
    /// </summary>
    public static IReadOnlyList<Violation> FindFontSizeLiteralViolations(
        IReadOnlyList<(string Path, string[] Lines)> axamlFiles)
    {
        var violations = new List<Violation>();

        foreach (var (path, lines) in axamlFiles)
        {
            for (var i = 0; i < lines.Length; i++)
            {
                var line = lines[i];
                if (FontSizeAttrRegex.IsMatch(line) || FontSizeSetterRegex.IsMatch(line))
                {
                    violations.Add(new Violation(path, i + 1, line.Trim(), "font-size-literal"));
                }
            }
        }

        violations.Sort((a, b) =>
        {
            var pc = string.CompareOrdinal(a.Path, b.Path);
            return pc != 0 ? pc : a.Line.CompareTo(b.Line);
        });
        return violations;
    }

    // ── Rule 3: no named-color keywords on brush attributes ──────────────

    // Matches a brush-bearing attribute whose value is a plain word (not a
    // markup extension, not a hex literal).  We then check whether the word
    // is "Transparent" (exempt) or something else (flag).
    private static readonly Regex BrushAttrRegex =
        new(@"(Foreground|Background|BorderBrush|Fill|Stroke)\s*=\s*""([^""{]*)""",
            RegexOptions.Compiled | RegexOptions.IgnoreCase);

    /// <summary>
    /// Returns every line where a brush-bearing attribute
    /// (<c>Foreground</c>, <c>Background</c>, <c>BorderBrush</c>,
    /// <c>Fill</c>, <c>Stroke</c>) carries a plain-word value that is
    /// neither <c>Transparent</c> nor a resource reference.
    /// </summary>
    public static IReadOnlyList<Violation> FindNamedColorViolations(
        IReadOnlyList<(string Path, string[] Lines)> axamlFiles)
    {
        var violations = new List<Violation>();

        foreach (var (path, lines) in axamlFiles)
        {
            for (var i = 0; i < lines.Length; i++)
            {
                var line = lines[i];
                var matches = BrushAttrRegex.Matches(line);
                foreach (Match m in matches)
                {
                    var value = m.Groups[2].Value.Trim();
                    // Skip hex, resource refs, {x:Null}, Transparent, empty.
                    if (value.Length == 0) continue;
                    if (value.StartsWith("#", StringComparison.Ordinal)) continue;
                    if (string.Equals(value, "Transparent", StringComparison.OrdinalIgnoreCase)) continue;

                    violations.Add(new Violation(path, i + 1, line.Trim(), "named-color"));
                    break; // one violation per line is enough
                }
            }
        }

        violations.Sort((a, b) =>
        {
            var pc = string.CompareOrdinal(a.Path, b.Path);
            return pc != 0 ? pc : a.Line.CompareTo(b.Line);
        });
        return violations;
    }

    // ── Rule 4: scan C# for programmatic color / font-size sites ─────────

    private static readonly Regex ColorParseRegex =
        new(@"Color\.Parse\(""#", RegexOptions.Compiled);

    private static readonly Regex ColorFromRgbRegex =
        new(@"Color\.FromRgb\(", RegexOptions.Compiled);

    private static readonly Regex ColorFromArgbRegex =
        new(@"Color\.FromArgb\(", RegexOptions.Compiled);

    // Colors.White, Colors.Red, …  but not Colors.Transparent.
    private static readonly Regex ColorsDotRegex =
        new(@"\bColors\.(\w+)", RegexOptions.Compiled);

    // Brushes.Gray, Brushes.White, … but not Brushes.Transparent.
    private static readonly Regex BrushesDotRegex =
        new(@"\bBrushes\.(\w+)", RegexOptions.Compiled);

    private static readonly Regex NewSolidColorBrushRegex =
        new(@"new\s+SolidColorBrush\(", RegexOptions.Compiled);

    private static readonly Regex BrushParseRegex =
        new(@"Brush\.Parse\(""#", RegexOptions.Compiled);

    private static readonly Regex BoxShadowsParseRegex =
        new(@"BoxShadows\.Parse\(", RegexOptions.Compiled);

    private static readonly Regex FontSizeAssignRegex =
        new(@"FontSize\s*=\s*\d+", RegexOptions.Compiled);

    /// <summary>
    /// Returns every line in <paramref name="csFiles"/> that contains a
    /// programmatic color / font-size literal, unless the file path is in
    /// <paramref name="allowListedPaths"/>.
    /// </summary>
    public static IReadOnlyList<Violation> FindCsViolations(
        IReadOnlyList<(string Path, string[] Lines)> csFiles,
        IReadOnlySet<string>? allowListedPaths = null)
    {
        var allowed = allowListedPaths ?? new HashSet<string>(StringComparer.Ordinal);
        var violations = new List<Violation>();

        foreach (var (path, lines) in csFiles)
        {
            if (IsAllowListed(path, allowed))
                continue;

            for (var i = 0; i < lines.Length; i++)
            {
                var line = lines[i];
                var rule = ClassifyCsLine(line);
                if (rule is not null)
                {
                    violations.Add(new Violation(path, i + 1, line.Trim(), rule));
                }
            }
        }

        violations.Sort((a, b) =>
        {
            var pc = string.CompareOrdinal(a.Path, b.Path);
            return pc != 0 ? pc : a.Line.CompareTo(b.Line);
        });
        return violations;
    }

    /// <summary>
    /// Classifies a single C# line.  Returns the rule name if it violates,
    /// or null if it is clean.
    /// </summary>
    private static string? ClassifyCsLine(string line)
    {
        if (ColorParseRegex.IsMatch(line))
            return "cs-color-parse";

        if (ColorFromRgbRegex.IsMatch(line))
            return "cs-color-fromrgb";

        if (ColorFromArgbRegex.IsMatch(line))
            return "cs-color-fromargb";

        if (BrushParseRegex.IsMatch(line))
            return "cs-brush-parse";

        if (BoxShadowsParseRegex.IsMatch(line))
            return "cs-boxshadows-parse";

        if (NewSolidColorBrushRegex.IsMatch(line))
            return "cs-solidcolorbrush";

        if (FontSizeAssignRegex.IsMatch(line))
            return "cs-fontsize";

        // Colors.White etc. — exempt Colors.Transparent
        var cm = ColorsDotRegex.Match(line);
        if (cm.Success && !string.Equals(cm.Groups[1].Value, "Transparent", StringComparison.Ordinal))
            return "cs-colors-dot";

        // Brushes.Gray etc. — exempt Brushes.Transparent
        var bm = BrushesDotRegex.Match(line);
        if (bm.Success && !string.Equals(bm.Groups[1].Value, "Transparent", StringComparison.Ordinal))
            return "cs-brushes-dot";

        return null;
    }

    // ── helpers ──────────────────────────────────────────────────────────

    /// <summary>
    /// Returns true when <paramref name="path"/> ends with any suffix in
    /// <paramref name="allowListedPaths"/> (case-insensitive ordinal).
    /// </summary>
    public static bool IsAllowListed(string path, IReadOnlySet<string> allowListedPaths)
    {
        foreach (var suffix in allowListedPaths)
        {
            if (path.EndsWith(suffix, StringComparison.Ordinal))
                return true;
        }

        return false;
    }
}

using VisualRelay.Guards;

namespace VisualRelay.Tests;

/// <summary>
/// Structural guard: every color and font-size literal must resolve to a
/// design token defined in Theme/Colors.axaml or Theme/Typography.axaml.
/// The guard covers four rule families: (1) no #-hex in .axaml outside the
/// two token files, (2) FontSize must be a resource reference, (3) no
/// named-color keywords on brush-bearing attributes, and (4) no programmatic
/// color/size literals in C#.  There is no baseline; the first run on the
/// pre-migration tree enumerates every offender.
/// </summary>
public sealed class DesignTokenCentralizationTests
{
    private static string RepoRoot => RepoSetup.Root;
    private static string AppSrcDir =>
        Path.Combine(RepoRoot, "src", "VisualRelay.App");

    private static readonly HashSet<string> TokenFileSuffixes =
        new(StringComparer.Ordinal)
        {
            "Theme/Colors.axaml",
            "Theme/Typography.axaml",
        };

    // ── Helpers ──────────────────────────────────────────────────────────

    private static List<(string Path, string[] Lines)> ReadAxamlFiles(string root)
    {
        if (!Directory.Exists(root))
            return [];
        return Directory.GetFiles(root, "*.axaml", SearchOption.AllDirectories)
            .OrderBy(f => f, StringComparer.Ordinal)
            .Select(f => (Path.GetRelativePath(RepoRoot, f), File.ReadAllLines(f)))
            .ToList();
    }

    private static List<(string Path, string[] Lines)> ReadCsFiles(string root)
    {
        if (!Directory.Exists(root))
            return [];
        return Directory.GetFiles(root, "*.cs", SearchOption.AllDirectories)
            .OrderBy(f => f, StringComparer.Ordinal)
            .Select(f => (Path.GetRelativePath(RepoRoot, f), File.ReadAllLines(f)))
            .ToList();
    }

    private static string FormatViolations(IReadOnlyList<DesignTokenGuard.Violation> violations)
    {
        return string.Join("\n",
            violations.Select((v, idx) =>
                $"  {idx + 1}. {v.Path}:{v.Line}  →  [{v.Rule}] {v.Text}"));
    }

    // ── In-memory unit tests (pure classifier) ───────────────────────────

    [Fact]
    public void HexLine_InAxaml_IsViolation()
    {
        var files = new (string Path, string[] Lines)[]
        {
            ("src/Views/Foo.axaml", new[] { @"<Border Background=""#1A1E25""/>" }),
        };

        var violations = DesignTokenGuard.FindHexViolations(files);

        Assert.Single(violations);
        Assert.Equal("hex-color", violations[0].Rule);
        Assert.Contains("#1A1E25", violations[0].Text, StringComparison.Ordinal);
    }

    [Fact]
    public void HexLine_InTokenFile_IsAllowed()
    {
        var files = new (string Path, string[] Lines)[]
        {
            ("src/Theme/Colors.axaml", new[] { @"<Color x:Key=""SurfaceColor"">#1A1E25</Color>" }),
        };

        var violations = DesignTokenGuard.FindHexViolations(files);

        Assert.Empty(violations);
    }

    [Fact]
    public void DynamicResource_PassesHexCheck()
    {
        var files = new (string Path, string[] Lines)[]
        {
            ("src/Views/Foo.axaml", new[] { @"<Border Background=""{DynamicResource SurfaceBrush}""/>" }),
        };

        var violations = DesignTokenGuard.FindHexViolations(files);

        Assert.Empty(violations);
    }

    [Fact]
    public void Transparent_Value_PassesHexCheck()
    {
        var files = new (string Path, string[] Lines)[]
        {
            ("src/Views/Foo.axaml", new[] { @"<Border Background=""Transparent""/>" }),
        };

        var violations = DesignTokenGuard.FindHexViolations(files);

        // Transparent has no #, so hex scan is empty
        Assert.Empty(violations);
    }

    [Fact]
    public void FontSizeNumericLiteral_IsViolation()
    {
        var files = new (string Path, string[] Lines)[]
        {
            ("src/Views/Foo.axaml", new[] { @"<TextBlock FontSize=""12""/>" }),
        };

        var violations = DesignTokenGuard.FindFontSizeLiteralViolations(files);

        Assert.Single(violations);
        Assert.Equal("font-size-literal", violations[0].Rule);
    }

    [Fact]
    public void FontSizeSetterNumericLiteral_IsViolation()
    {
        var files = new (string Path, string[] Lines)[]
        {
            ("src/Styles/Theme.axaml", new[] { @"<Setter Property=""FontSize"" Value=""10""/>" }),
        };

        var violations = DesignTokenGuard.FindFontSizeLiteralViolations(files);

        Assert.Single(violations);
        Assert.Equal("font-size-literal", violations[0].Rule);
    }

    [Fact]
    public void FontSizeStaticResource_Passes()
    {
        var files = new (string Path, string[] Lines)[]
        {
            ("src/Views/Foo.axaml", new[] { @"<TextBlock FontSize=""{StaticResource FontSizeBody}""/>" }),
        };

        var violations = DesignTokenGuard.FindFontSizeLiteralViolations(files);

        Assert.Empty(violations);
    }

    [Fact]
    public void FontSizeDynamicResource_Passes()
    {
        var files = new (string Path, string[] Lines)[]
        {
            ("src/Views/Foo.axaml", new[] { @"<TextBlock FontSize=""{DynamicResource FontSizeBody}""/>" }),
        };

        var violations = DesignTokenGuard.FindFontSizeLiteralViolations(files);

        Assert.Empty(violations);
    }

    [Fact]
    public void WidthNumericLiteral_IsIgnored()
    {
        var files = new (string Path, string[] Lines)[]
        {
            ("src/Views/Foo.axaml", new[] { @"<Border Width=""12""/>" }),
        };

        var violations = DesignTokenGuard.FindFontSizeLiteralViolations(files);

        Assert.Empty(violations);
    }

    [Fact]
    public void NamedColorOnForeground_IsViolation()
    {
        var files = new (string Path, string[] Lines)[]
        {
            ("src/Views/Foo.axaml", new[] { @"<TextBlock Foreground=""Red""/>" }),
        };

        var violations = DesignTokenGuard.FindNamedColorViolations(files);

        Assert.Single(violations);
        Assert.Equal("named-color", violations[0].Rule);
    }

    [Fact]
    public void TransparentOnForeground_Passes()
    {
        var files = new (string Path, string[] Lines)[]
        {
            ("src/Views/Foo.axaml", new[] { @"<Border Background=""Transparent""/>" }),
        };

        var violations = DesignTokenGuard.FindNamedColorViolations(files);

        Assert.Empty(violations);
    }

    [Fact]
    public void XNullOnBorderBrush_IsNotNamedColor()
    {
        var files = new (string Path, string[] Lines)[]
        {
            ("src/Views/Foo.axaml", new[] { @"<Border BorderBrush=""{x:Null}""/>" }),
        };

        var violations = DesignTokenGuard.FindNamedColorViolations(files);

        // {x:Null} starts with { — not matched by the brush-attr regex
        Assert.Empty(violations);
    }

    [Fact]
    public void HexOnBackground_IsNotFlaggedAsNamedColor()
    {
        var files = new (string Path, string[] Lines)[]
        {
            ("src/Views/Foo.axaml", new[] { @"<Border Background=""#1A1E25""/>" }),
        };

        var violations = DesignTokenGuard.FindNamedColorViolations(files);

        // Hex starts with # — ruled out by the named-color classifier
        Assert.Empty(violations);
    }

    [Fact]
    public void CsColorParse_IsViolation()
    {
        var files = new (string Path, string[] Lines)[]
        {
            ("src/Foo.cs", new[] { @"var b = new SolidColorBrush(Color.Parse(""#6F7785""));" }),
        };

        var violations = DesignTokenGuard.FindCsViolations(files);

        Assert.NotEmpty(violations);
        // Should match both Color.Parse and new SolidColorBrush
        Assert.Contains(violations, v => v.Rule == "cs-color-parse");
    }

    [Fact]
    public void CsSolidColorBrush_IsViolation()
    {
        var files = new (string Path, string[] Lines)[]
        {
            ("src/Foo.cs", new[] { @"new SolidColorBrush(Colors.Red)" }),
        };

        var violations = DesignTokenGuard.FindCsViolations(files);

        Assert.NotEmpty(violations);
        Assert.Contains(violations, v => v.Rule == "cs-solidcolorbrush");
    }

    [Fact]
    public void CsBrushesGray_IsViolation()
    {
        var files = new (string Path, string[] Lines)[]
        {
            ("src/Foo.cs", new[] { @"Foreground ?? Brushes.Gray" }),
        };

        var violations = DesignTokenGuard.FindCsViolations(files);

        Assert.NotEmpty(violations);
        Assert.Contains(violations, v => v.Rule == "cs-brushes-dot");
    }

    [Fact]
    public void CsBrushesTransparent_IsAllowed()
    {
        var files = new (string Path, string[] Lines)[]
        {
            ("src/Foo.cs", new[] { @"Brushes.Transparent" }),
        };

        var violations = DesignTokenGuard.FindCsViolations(files);

        Assert.Empty(violations);
    }

    [Fact]
    public void CsColorsTransparent_IsAllowed()
    {
        var files = new (string Path, string[] Lines)[]
        {
            ("src/Foo.cs", new[] { @"Colors.Transparent" }),
        };

        var violations = DesignTokenGuard.FindCsViolations(files);

        Assert.Empty(violations);
    }

    [Fact]
    public void CsBrushParse_IsViolation()
    {
        var files = new (string Path, string[] Lines)[]
        {
            ("src/Foo.cs", new[] { @"Brush.Parse(""#1A1E26"")" }),
        };

        var violations = DesignTokenGuard.FindCsViolations(files);

        Assert.NotEmpty(violations);
        Assert.Contains(violations, v => v.Rule == "cs-brush-parse");
    }

    [Fact]
    public void CsBoxShadowsParse_IsViolation()
    {
        var files = new (string Path, string[] Lines)[]
        {
            ("src/Foo.cs", new[] { @"BoxShadows.Parse(""0 0 0 0 #00000000"")" }),
        };

        var violations = DesignTokenGuard.FindCsViolations(files);

        Assert.NotEmpty(violations);
        Assert.Contains(violations, v => v.Rule == "cs-boxshadows-parse");
    }

    [Fact]
    public void CsFontSizeAssign_IsViolation()
    {
        var files = new (string Path, string[] Lines)[]
        {
            ("src/Foo.cs", new[] { @"FontSize = 14" }),
        };

        var violations = DesignTokenGuard.FindCsViolations(files);

        Assert.NotEmpty(violations);
        Assert.Contains(violations, v => v.Rule == "cs-fontsize");
    }

    [Fact]
    public void CsAllowListedFile_Passes()
    {
        var files = new (string Path, string[] Lines)[]
        {
            ("src/Constants.cs", new[] { @"public const string Surface = ""#1A1E25"";" }),
        };

        var allowed = new HashSet<string>(StringComparer.Ordinal) { "Constants.cs" };
        var violations = DesignTokenGuard.FindCsViolations(files, allowed);

        Assert.Empty(violations);
    }

    [Fact]
    public void [ENCRYPTED:fastly]-ddnyRDMc_HcR2UNfN186Pj0p_QexcKE()
    {
        var files = new (string Path, string[] Lines)[]
        {
            ("zzz/Last.axaml",  new[] { @"", @"<Border Background=""#CCC""/>" }),
            ("aaa/First.axaml", new[] { @"<Border Background=""#AAA""/>" }),
        };

        var violations = DesignTokenGuard.FindHexViolations(files);

        Assert.Equal(2, violations.Count);
        Assert.Equal("aaa/First.axaml", violations[0].Path);
        Assert.Equal("zzz/Last.axaml", violations[1].Path);
        Assert.Equal(2, violations[1].Line);
    }

    [Fact]
    public void MultipleHexOnSameLine_OneViolation()
    {
        var files = new (string Path, string[] Lines)[]
        {
            ("src/Foo.axaml", new[] { @"<Border Background=""#AAA"" BorderBrush=""#BBB""/>" }),
        };

        var violations = DesignTokenGuard.FindHexViolations(files);

        // One line → one violation (the line is flagged once)
        Assert.Single(violations);
    }

    // ── Real-tree scan ───────────────────────────────────────────────────

    [Fact]
    public void DesignTokenGuard_NoRawLiterals_InAppSource()
    {
        var axamlFiles = ReadAxamlFiles(AppSrcDir);
        Assert.True(axamlFiles.Count > 0,
            $"No .axaml files found under {AppSrcDir}.");

        var csFiles = ReadCsFiles(AppSrcDir);
        Assert.True(csFiles.Count > 0,
            $"No .cs files found under {AppSrcDir}.");

        var hexViolations = DesignTokenGuard.FindHexViolations(axamlFiles);
        var fontSizeViolations = DesignTokenGuard.FindFontSizeLiteralViolations(axamlFiles);
        var namedColorViolations = DesignTokenGuard.FindNamedColorViolations(axamlFiles);
        var csViolations = DesignTokenGuard.FindCsViolations(csFiles);

        var allViolations = new List<DesignTokenGuard.Violation>();
        allViolations.AddRange(hexViolations);
        allViolations.AddRange(fontSizeViolations);
        allViolations.AddRange(namedColorViolations);
        allViolations.AddRange(csViolations);
        allViolations.Sort((a, b) =>
        {
            var pc = string.CompareOrdinal(a.Path, b.Path);
            return pc != 0 ? pc : a.Line.CompareTo(b.Line);
        });

        Assert.True(allViolations.Count == 0,
            $"Found {allViolations.Count} raw color/font-size literal(s) in "
            + $"src/VisualRelay.App.  Every color and FontSize must resolve to a "
            + $"design token from Theme/Colors.axaml or Theme/Typography.axaml.\n\n"
            + $"Violations:\n{FormatViolations(allViolations)}");
    }
}

using System.Globalization;
using System.Text.RegularExpressions;

namespace VisualRelay.Tests;

/// <summary>
/// WCAG 2.2 AA accessibility assertions for the centralised design tokens.
/// Pure relative-luminance / contrast-ratio math (unit-tested against known
/// pairs) plus a real-tree [Fact] that parses Theme/Colors.axaml and
/// Theme/Typography.axaml and verifies every declared foreground/background
/// pairing meets its AA threshold, and that no font-size token is below
/// 12px.
/// </summary>
public sealed class DesignTokenAccessibilityTests
{
    // ── WCAG 2.2 relative luminance & contrast ratio (pure) ──────────────

    /// <summary>
    /// sRGB to linearised component per WCAG 2.2 § 7.1.1.
    /// </summary>
    private static double Linearise(double channel8Bit)
    {
        var c = channel8Bit / 255.0;
        return c <= 0.04045 ? c / 12.92 : Math.Pow((c + 0.055) / 1.055, 2.4);
    }

    /// <summary>
    /// WCAG 2.2 relative luminance of an sRGB colour (0–255 per channel).
    /// </summary>
    public static double RelativeLuminance(int r, int g, int b)
    {
        return 0.2126 * Linearise(r) + 0.7152 * Linearise(g) + 0.0722 * Linearise(b);
    }

    /// <summary>
    /// WCAG 2.2 contrast ratio between two relative luminances.
    /// Lighter / darker so the result is always ≥ 1.
    /// </summary>
    public static double ContrastRatio(double l1, double l2)
    {
        var lighter = Math.Max(l1, l2);
        var darker = Math.Min(l1, l2);
        return (lighter + 0.05) / (darker + 0.05);
    }

    /// <summary>
    /// Convenience: contrast ratio between two sRGB colours (0–255 per
    /// channel).
    /// </summary>
    public static double ContrastRatio(int r1, int g1, int b1, int r2, int g2, int b2)
    {
        return ContrastRatio(RelativeLuminance(r1, g1, b1), RelativeLuminance(r2, g2, b2));
    }

    /// <summary>AA normal-text threshold (≥ 4.5:1).</summary>
    public const double AaNormalText = 4.5;

    /// <summary>AA large-text / non-text-UI threshold (≥ 3:1).</summary>
    public const double AaLargeText = 3.0;

    // ── Unit tests for the contrast math ─────────────────────────────────

    [Fact]
    public void BlackOnWhite_ContrastRatio_Is21()
    {
        var ratio = ContrastRatio(0, 0, 0, 255, 255, 255);
        Assert.Equal(21.0, ratio, 0.05); // within 0.05 tolerance
    }

    [Fact]
    public void WhiteOnBlack_ContrastRatio_Is21()
    {
        var ratio = ContrastRatio(255, 255, 255, 0, 0, 0);
        Assert.Equal(21.0, ratio, 0.05);
    }

    [Fact]
    public void IdenticalColors_ContrastRatio_Is1()
    {
        var ratio = ContrastRatio(128, 128, 128, 128, 128, 128);
        Assert.Equal(1.0, ratio, 0.01);
    }

    [Fact]
    public void RedOnWhite_KnownContrast()
    {
        // Pure red (#FF0000) on white: luminance ≈ 0.2126, contrast ≈ 4.0
        var ratio = ContrastRatio(255, 0, 0, 255, 255, 255);
        Assert.True(ratio < 4.5, $"Red-on-white contrast {ratio:F2} — expected below 4.5");
        Assert.True(ratio > 3.5, $"Red-on-white contrast {ratio:F2} — expected above 3.5");
    }

    [Fact]
    public void WhiteOnBlue_KnownContrast()
    {
        // White on #5B7CFA (91,124,250)
        var ratio = ContrastRatio(255, 255, 255, 91, 124, 250);
        Assert.True(ratio > 3.0, $"White-on-accent contrast {ratio:F2} — expected above 3:1");
    }

    [Fact]
    public void RelativeLuminance_Black_IsZero()
    {
        var lum = RelativeLuminance(0, 0, 0);
        Assert.Equal(0.0, lum, 0.001);
    }

    [Fact]
    public void RelativeLuminance_White_IsOne()
    {
        var lum = RelativeLuminance(255, 255, 255);
        Assert.Equal(1.0, lum, 0.001);
    }

    // ── Hex parsing helpers ──────────────────────────────────────────────

    private static readonly Regex HexColorRegex =
        new(@"#([0-9A-Fa-f]{2})([0-9A-Fa-f]{2})([0-9A-Fa-f]{2})(?:[0-9A-Fa-f]{2})?",
            RegexOptions.Compiled);

    /// <summary>
    /// Parses a hex string like <c>#1A1E25</c> or <c>#FF1A1E25</c> into
    /// (r, g, b).  Returns null on failure.
    /// </summary>
    private static (int r, int g, int b)? ParseHex(string hex)
    {
        var m = HexColorRegex.Match(hex);
        if (!m.Success) return null;
        return (
            int.Parse(m.Groups[1].Value, NumberStyles.HexNumber, CultureInfo.InvariantCulture),
            int.Parse(m.Groups[2].Value, NumberStyles.HexNumber, CultureInfo.InvariantCulture),
            int.Parse(m.Groups[3].Value, NumberStyles.HexNumber, CultureInfo.InvariantCulture)
        );
    }

    // Matches a SolidColorBrush resource: Color="#RRGGBB"
    private static readonly Regex BrushResourceRegex =
        new(@"Color\s*=\s*""(#[0-9A-Fa-f]{6,8})""",
            RegexOptions.Compiled);

    // Matches a Color resource: <Color x:Key="...">#RRGGBB</Color>
    private static readonly Regex ColorResourceRegex =
        new(@"<Color\s+x:Key\s*=\s*""([^""]+)""[^>]*>\s*(#[0-9A-Fa-f]{6,8})\s*</Color>",
            RegexOptions.Compiled);

    // Matches a font-size token: <x:Double x:Key="...">N</x:Double>
    private static readonly Regex FontSizeResourceRegex =
        new(@"<x:Double\s+x:Key\s*=\s*""([^""]+)""[^>]*>\s*(\d+(?:\.\d+)?)\s*</x:Double>",
            RegexOptions.Compiled);

    // ── Real-tree accessibility assertions ───────────────────────────────

    /// <summary>
    /// Parses Theme/Colors.axaml and Theme/Typography.axaml, then verifies
    /// every declared foreground/background pairing meets WCAG 2.2 AA, and
    /// that no font-size token is below 12 px.
    /// </summary>
    [Fact]
    public void DesignTokens_MeetAccessibilityThresholds()
    {
        var repoRoot = RepoSetup.Root;
        var colorsPath = Path.Combine(repoRoot, "src", "VisualRelay.App", "Theme", "Colors.axaml");
        var typographyPath = Path.Combine(repoRoot, "src", "VisualRelay.App", "Theme", "Typography.axaml");

        Assert.True(File.Exists(colorsPath),
            $"Theme/Colors.axaml not found at {colorsPath}.  "
            + "Create it with semantic Color + SolidColorBrush resources.");
        Assert.True(File.Exists(typographyPath),
            $"Theme/Typography.axaml not found at {typographyPath}.  "
            + "Create it with x:Double font-size resources.");

        // Parse colors into a name → (r, g, b) map.
        var colorsText = File.ReadAllText(colorsPath);
        var palette = new Dictionary<string, (int r, int g, int b)>(StringComparer.Ordinal);

        foreach (Match m in ColorResourceRegex.Matches(colorsText))
        {
            var name = m.Groups[1].Value;
            var hex = m.Groups[2].Value;
            var rgb = ParseHex(hex);
            if (rgb.HasValue)
                palette[name] = rgb.Value;
        }

        // Also parse SolidColorBrush definitions (Color="#...").
        foreach (Match m in BrushResourceRegex.Matches(colorsText))
        {
            var hex = m.Groups[1].Value;
            var rgb = ParseHex(hex);
            if (rgb.HasValue)
            {
                // We need the key — it's on the same element earlier.
                // Extract the x:Key from the full element text.
                var fullElement = GetEnclosingElement(colorsText, m.Index);
                var keyMatch = Regex.Match(fullElement, @"x:Key\s*=\s*""([^""]+)""");
                if (keyMatch.Success)
                {
                    var name = keyMatch.Groups[1].Value;
                    if (!palette.ContainsKey(name))
                        palette[name] = rgb.Value;
                }
            }
        }

        Assert.True(palette.Count > 0,
            "No color resources found in Theme/Colors.axaml.  "
            + "Define semantic Color and/or SolidColorBrush resources.");

        // ── Font-size floor: no token below 12 ──────────────────────────

        var typographyText = File.ReadAllText(typographyPath);
        var fontSizeTokens = new Dictionary<string, double>(StringComparer.Ordinal);
        foreach (Match m in FontSizeResourceRegex.Matches(typographyText))
        {
            var name = m.Groups[1].Value;
            var value = double.Parse(m.Groups[2].Value, CultureInfo.InvariantCulture);
            fontSizeTokens[name] = value;
        }

        Assert.True(fontSizeTokens.Count > 0,
            "No font-size tokens found in Theme/Typography.axaml.  "
            + "Define x:Double resources for each distinct font size.");

        var tooSmall = new List<string>();
        foreach (var (name, value) in fontSizeTokens.OrderBy(kv => kv.Value))
        {
            if (value < 12.0)
                tooSmall.Add($"  {name} = {value}px (minimum is 12px)");
        }

        Assert.True(tooSmall.Count == 0,
            $"Found {tooSmall.Count} font-size token(s) below the 12px floor:\n"
            + string.Join("\n", tooSmall));

        // ── Contrast pairings ───────────────────────────────────────────
        // Encode the design's actual text-on-surface combinations so any
        // future token edit that breaks contrast fails here.

        var failures = new List<string>();

        // Helper to check a pairing if both tokens exist.
        void CheckPair(string fgName, string bgName, double threshold, string label)
        {
            if (!palette.TryGetValue(fgName, out var fg))
            {
                failures.Add($"  Missing foreground token: {fgName}");
                return;
            }

            if (!palette.TryGetValue(bgName, out var bg))
            {
                failures.Add($"  Missing background token: {bgName}");
                return;
            }

            var ratio = ContrastRatio(fg.r, fg.g, fg.b, bg.r, bg.g, bg.b);
            if (ratio < threshold)
            {
                failures.Add(
                    $"  {label}: {fgName} on {bgName} = {ratio:F2}:1 "
                    + $"(need ≥ {threshold}:1)");
            }
        }

        // Text-on-surface pairings (4.5:1 for normal text).
        // These are the primary text colors on the main surface backgrounds.
        // The token names below must match what Colors.axaml defines.
        CheckPair("TextPrimaryBrush", "PanelBgBrush", AaNormalText,
            "Primary text on panel background");
        CheckPair("TextPrimaryBrush", "SurfaceBrush", AaNormalText,
            "Primary text on surface");
        CheckPair("TextPrimaryBrush", "CardBgBrush", AaNormalText,
            "Primary text on card");
        CheckPair("TextHeadingBrush", "PanelBgBrush", AaNormalText,
            "Heading text on panel");
        CheckPair("TextSubtleBrush", "PanelBgBrush", AaNormalText,
            "Subtle text on panel (e.g. chevron, collapse toggle)");
        CheckPair("TextMutedBrush", "PanelBgBrush", AaNormalText,
            "Muted text on panel");
        CheckPair("TextPrimaryBrush", "WindowBgBrush", AaNormalText,
            "Primary text on window background");

        // Large-text / UI pairings (3:1).
        CheckPair("AccentBrush", "SurfaceBrush", AaLargeText,
            "Accent on surface (button)");
        CheckPair("AccentBrush", "FocusToggleBgBrush", AaLargeText,
            "Focus-toggle foreground on background");
        CheckPair("FocusToggleTextBrush", "FocusToggleBgBrush", AaLargeText,
            "Focus-toggle text on background");
        CheckPair("WarningBrush", "WarningBgBrush", AaLargeText,
            "Warning text on warning background");
        CheckPair("SelectionBrush", "SelectedBgBrush", AaLargeText,
            "Selection indicator on selected background");
        CheckPair("ErrorBrush", "ErrorBgBrush", AaLargeText,
            "Error text on error background");

        // Accent-on-dark pairings (>3:1 for non-text UI like borders).
        CheckPair("SelectionBrush", "CardBgBrush", AaLargeText,
            "Selection border on card");

        Assert.True(failures.Count == 0,
            $"Found {failures.Count} accessibility violation(s) in design tokens:\n"
            + string.Join("\n", failures));
    }

    /// <summary>
    /// Given an index within a text block, walks backward to the start of
    /// the enclosing XML element and forward to its closing, returning the
    /// full element string.
    /// </summary>
    private static string GetEnclosingElement(string text, int index)
    {
        // Walk back to find '<'
        var start = text.LastIndexOf('<', index);
        if (start < 0) return string.Empty;

        // Walk forward to find the matching '>' or "/>"
        var depth = 0;
        var inString = false;
        var inComment = false;
        for (var i = start; i < text.Length; i++)
        {
            var c = text[i];

            if (!inString && !inComment && c == '<' && i + 4 < text.Length
                && text[i + 1] == '!' && text[i + 2] == '-' && text[i + 3] == '-')
            {
                inComment = true;
                i += 3;
                continue;
            }

            if (inComment && c == '-' && i + 2 < text.Length
                && text[i + 1] == '-' && text[i + 2] == '>')
            {
                inComment = false;
                i += 2;
                continue;
            }

            if (inComment) continue;

            if (c == '"') inString = !inString;
            if (inString) continue;

            if (c == '<') depth++;
            else if (c == '>')
            {
                depth--;
                if (depth == 0)
                    return text[start..(i + 1)];
            }
        }

        return string.Empty;
    }
}

using VisualRelay.Guards;

namespace VisualRelay.Tests;

/// <summary>
/// In-memory unit tests for <see cref="DesignTokenGuard"/> pure
/// classification functions.  Each rule family is exercised with
/// synthetic inputs so the classifiers are proven correct independent
/// of the real source tree.
/// </summary>
public sealed class DesignTokenCentralizationTests
{
    // ── Rule 1: hex literals in .axaml ──────────────────────────────────

    [Fact]
    public void HexLine_InAxaml_IsViolation()
    {
        var files = new (string, string[])[] {
            ("src/Views/Foo.axaml", new[] { @"<Border Background=""#1A1E25""/>" }),
        };
        var v = DesignTokenGuard.FindHexViolations(files);
        Assert.Single(v);
        Assert.Equal("hex-color", v[0].Rule);
        Assert.Contains("#1A1E25", v[0].Text, StringComparison.Ordinal);
    }

    [Fact]
    public void HexLine_InTokenFile_IsAllowed()
    {
        var files = new (string, string[])[] {
            ("src/Theme/Colors.axaml", new[] { @"<Color x:Key=""S"">#1A1E25</Color>" }),
