using VisualRelay.Guards;

namespace VisualRelay.Tests;

/// <summary>
/// Real-tree scan: enumerates every <c>*.axaml</c> and <c>*.cs</c> file
/// under <c>src/VisualRelay.App</c> and asserts zero raw color / font-size
/// literals.  The two token files (Theme/Colors.axaml, Theme/Typography.axaml)
/// are the sole allow-listed home for raw hex literals.
///
/// This test is intentionally separate from the in-memory classifier tests
/// so both files stay under the 300-line FileSizeGuard limit.
/// </summary>
public sealed class DesignTokenCentralizationGuardTests
{
    private static string RepoRoot => RepoSetup.Root;
    private static string AppSrcDir =>
        Path.Combine(RepoRoot, "src", "VisualRelay.App");

    private static List<(string Path, string[] Lines)> ReadAxamlFiles(string root)
    {
        if (!Directory.Exists(root)) return [];
        return Directory.GetFiles(root, "*.axaml", SearchOption.AllDirectories)
            .OrderBy(f => f, StringComparer.Ordinal)
            .Select(f => (Path.GetRelativePath(RepoRoot, f), File.ReadAllLines(f)))
            .ToList();
    }

    private static List<(string Path, string[] Lines)> ReadCsFiles(string root)
    {
        if (!Directory.Exists(root)) return [];
        return Directory.GetFiles(root, "*.cs", SearchOption.AllDirectories)
            .OrderBy(f => f, StringComparer.Ordinal)
            .Select(f => (Path.GetRelativePath(RepoRoot, f), File.ReadAllLines(f)))
            .ToList();
    }

    private static string FormatViolations(IReadOnlyList<DesignTokenGuard.Violation> violations)
    {
        return string.Join("\n",
            violations.Select((v, idx) =>
                $"  {idx + 1}. {v.Path}:{v.Line}  →  [{v.Rule}] {v.Text}"));
    }

    [Fact]
    public void DesignTokenGuard_NoRawLiterals_InAppSource()
    {
        var axamlFiles = ReadAxamlFiles(AppSrcDir);
        Assert.True(axamlFiles.Count > 0,
            $"No .axaml files found under {AppSrcDir}.");

        var csFiles = ReadCsFiles(AppSrcDir);
        Assert.True(csFiles.Count > 0,
            $"No .cs files found under {AppSrcDir}.");

        var all = new List<DesignTokenGuard.Violation>();
        all.AddRange(DesignTokenGuard.FindHexViolations(axamlFiles));
        all.AddRange(DesignTokenGuard.FindFontSizeLiteralViolations(axamlFiles));
        all.AddRange(DesignTokenGuard.FindNamedColorViolations(axamlFiles));
        all.AddRange(DesignTokenGuard.FindCsViolations(csFiles));
        all.Sort((a, b) =>
        {
            var pc = string.CompareOrdinal(a.Path, b.Path);
            return pc != 0 ? pc : a.Line.CompareTo(b.Line);
        });

        Assert.True(all.Count == 0,
            $"Found {all.Count} raw color/font-size literal(s) in "
            + $"src/VisualRelay.App.  Every color and FontSize must resolve to a "
            + $"design token from Theme/Colors.axaml or Theme/Typography.axaml.\n\n"
            + $"Violations:\n{FormatViolations(all)}");
    }
}

namespace VisualRelay.Tests;

/// <summary>
/// Pure WCAG 2.2 relative-luminance / contrast-ratio math, unit-tested
/// against known colour pairs.  These functions are used by
/// <see cref="DesignTokenAccessibilityGuardTests"/> to verify the
/// centralised design tokens meet AA thresholds.
/// </summary>
public sealed class DesignTokenAccessibilityTests
{
    // ── WCAG 2.2 relative luminance & contrast ratio (pure) ─────────────

    /// <summary>sRGB to linearised component per WCAG 2.2 § 7.1.1.</summary>
    private static double Linearise(double channel8Bit)
    {
        var c = channel8Bit / 255.0;
        return c <= 0.04045 ? c / 12.92 : Math.Pow((c + 0.055) / 1.055, 2.4);
    }

    /// <summary>WCAG 2.2 relative luminance of an sRGB colour (0–255 per channel).</summary>
    public static double RelativeLuminance(int r, int g, int b)
    {
        return 0.2126 * Linearise(r) + 0.7152 * Linearise(g) + 0.0722 * Linearise(b);
    }

    /// <summary>
    /// WCAG 2.2 contrast ratio between two relative luminances.
    /// Lighter / darker so the result is always ≥ 1.
    /// </summary>
    public static double ContrastRatio(double l1, double l2)
    {
        var lighter = Math.Max(l1, l2);
        var darker = Math.Min(l1, l2);
        return (lighter + 0.05) / (darker + 0.05);
    }

    /// <summary>Contrast ratio between two sRGB colours (0–255 per channel).</summary>
    public static double ContrastRatio(int r1, int g1, int b1, int r2, int g2, int b2)
    {
        return ContrastRatio(RelativeLuminance(r1, g1, b1), RelativeLuminance(r2, g2, b2));
    }

    /// <summary>AA normal-text threshold (≥ 4.5:1).</summary>
    public const double AaNormalText = 4.5;

    /// <summary>AA large-text / non-text-UI threshold (≥ 3:1).</summary>
    public const double AaLargeText = 3.0;

    // ── Unit tests for the contrast math ─────────────────────────────────

    [Fact]
    public void BlackOnWhite_ContrastRatio_Is21()
    {
        var ratio = ContrastRatio(0, 0, 0, 255, 255, 255);
        Assert.Equal(21.0, ratio, 0.05);
    }

    [Fact]
    public void WhiteOnBlack_ContrastRatio_Is21()
    {
        var ratio = ContrastRatio(255, 255, 255, 0, 0, 0);
        Assert.Equal(21.0, ratio, 0.05);
    }

    [Fact]
    public void IdenticalColors_ContrastRatio_Is1()
    {
        var ratio = ContrastRatio(128, 128, 128, 128, 128, 128);
        Assert.Equal(1.0, ratio, 0.01);
    }

    [Fact]
    public void RedOnWhite_Contrast_BelowNormalText()
    {
        // Pure red (#FF0000) on white: ≈ 4.0 — fails AA normal text.
        var ratio = ContrastRatio(255, 0, 0, 255, 255, 255);
        Assert.True(ratio < 4.5, $"Red-on-white {ratio:F2} — expected below 4.5");
        Assert.True(ratio > 3.5, $"Red-on-white {ratio:F2} — expected above 3.5");
    }

    [Fact]
    public void WhiteOnDarkBlue_Contrast_AboveLargeText()
    {
        // White on #5B7CFA (91,124,250)
        var ratio = ContrastRatio(255, 255, 255, 91, 124, 250);
        Assert.True(ratio > 3.0, $"White-on-accent {ratio:F2} — expected above 3:1");
    }

    [Fact]
    public void RelativeLuminance_Black_IsZero()
    {
        Assert.Equal(0.0, RelativeLuminance(0, 0, 0), 0.001);
    }

    [Fact]
    public void RelativeLuminance_White_IsOne()
    {
        Assert.Equal(1.0, RelativeLuminance(255, 255, 255), 0.001);
    }

    [Fact]
    public void MutedTextOnDarkPanel_KnownLowContrast()
    {
        // #6F7785 (111,119,133) on #12151B (18,21,27) — the pre-migration chevron.
        var ratio = ContrastRatio(111, 119, 133, 18, 21, 27);
        Assert.True(ratio < 4.5,
            $"Muted-on-dark contrast {ratio:F2} — expected below 4.5 (needs fix in accessibility pass)");
    }

    [Fact]
    public void WarningOnWarningBg_KnownContrast()
    {
        // #F0CA66 (240,202,102) on #2B2416 (43,36,22)
        var ratio = ContrastRatio(240, 202, 102, 43, 36, 22);
        Assert.True(ratio > 1.0, "Warning contrast should be measurable");
    }

    [Fact]
    public void ContrastRatio_IsSymmetric()
    {
        var a = ContrastRatio(100, 150, 200, 30, 40, 50);
        var b = ContrastRatio(30, 40, 50, 100, 150, 200);
        Assert.Equal(a, b, 0.0001);
    }
}

using System.Globalization;
using System.Text.RegularExpressions;

namespace VisualRelay.Tests;

/// <summary>
/// Real-tree scan: parses Theme/Colors.axaml and Theme/Typography.axaml,
/// then verifies every declared foreground/background pairing meets WCAG
/// 2.2 AA contrast thresholds, and that no font-size token is below 12 px.
///
/// Intentionally separate from <see cref="DesignTokenAccessibilityTests"/>
/// so both files stay under the 300-line FileSizeGuard limit.
/// </summary>
public sealed class DesignTokenAccessibilityGuardTests
{
    // ── Hex parsing helpers ──────────────────────────────────────────────

    private static readonly Regex HexColorRegex =
        new(@"#([0-9A-Fa-f]{2})([0-9A-Fa-f]{2})([0-9A-Fa-f]{2})(?:[0-9A-Fa-f]{2})?",
            RegexOptions.Compiled);

    private static (int r, int g, int b)? ParseHex(string hex)
    {
        var m = HexColorRegex.Match(hex);
        if (!m.Success) return null;
        return (
            int.Parse(m.Groups[1].Value, NumberStyles.HexNumber, CultureInfo.InvariantCulture),
            int.Parse(m.Groups[2].Value, NumberStyles.HexNumber, CultureInfo.InvariantCulture),
            int.Parse(m.Groups[3].Value, NumberStyles.HexNumber, CultureInfo.InvariantCulture)
        );
    }

    private static readonly Regex ColorResourceRegex =
        new(@"<Color\s+x:Key\s*=\s*""([^""]+)""[^>]*>\s*(#[0-9A-Fa-f]{6,8})\s*</Color>",
            RegexOptions.Compiled);

    private static readonly Regex BrushKeyRegex =
        new(@"x:Key\s*=\s*""([^""]+)""", RegexOptions.Compiled);

    private static readonly Regex BrushColorRegex =
        new(@"Color\s*=\s*""(#[0-9A-Fa-f]{6,8})""", RegexOptions.Compiled);

    private static readonly Regex FontSizeRegex =
        new(@"<x:Double\s+x:Key\s*=\s*""([^""]+)""[^>]*>\s*(\d+(?:\.\d+)?)\s*</x:Double>",
            RegexOptions.Compiled);

    // ── Element-boundary helper ──────────────────────────────────────────

    /// <summary>
    /// Given an index within text, walks backward to the start of the
    /// enclosing XML element and forward to its closing, returning the
    /// full element string.
    /// </summary>
    private static string GetEnclosingElement(string text, int index)
    {
        var start = text.LastIndexOf('<', index);
        if (start < 0) return string.Empty;

        var depth = 0;
        var inString = false;
        var inComment = false;
        for (var i = start; i < text.Length; i++)
        {
            var c = text[i];
            if (!inString && !inComment && c == '<' && i + 4 < text.Length
                && text[i + 1] == '!' && text[i + 2] == '-' && text[i + 3] == '-')
            { inComment = true; i += 3; continue; }
            if (inComment && c == '-' && i + 2 < text.Length
                && text[i + 1] == '-' && text[i + 2] == '>')
            { inComment = false; i += 2; continue; }
            if (inComment) continue;
            if (c == '"') inString = !inString;
            if (inString) continue;
            if (c == '<') depth++;
            else if (c == '>') { depth--; if (depth == 0) return text[start..(i + 1)]; }
        }

        return string.Empty;
    }

    // ── The real-tree assertion ──────────────────────────────────────────

    [Fact]
    public void DesignTokens_MeetAccessibilityThresholds()
    {
        var repoRoot = RepoSetup.Root;
        var colorsPath = Path.Combine(repoRoot, "src", "VisualRelay.App", "Theme", "Colors.axaml");
        var typographyPath = Path.Combine(repoRoot, "src", "VisualRelay.App", "Theme", "Typography.axaml");

        Assert.True(File.Exists(colorsPath),
            $"Theme/Colors.axaml not found at {colorsPath}.  "
            + "Create it with semantic Color + SolidColorBrush resources.");
        Assert.True(File.Exists(typographyPath),
            $"Theme/Typography.axaml not found at {typographyPath}.  "
            + "Create it with x:Double font-size resources.");

        // ── Parse colour palette ────────────────────────────────────────
        var colorsText = File.ReadAllText(colorsPath);
        var palette = new Dictionary<string, (int r, int g, int b)>(StringComparer.Ordinal);

        foreach (Match m in ColorResourceRegex.Matches(colorsText))
        {
            var name = m.Groups[1].Value;
            var rgb = ParseHex(m.Groups[2].Value);
            if (rgb.HasValue) palette[name] = rgb.Value;
        }

        // Parse SolidColorBrush resources too: find Color="#..." and walk
        // back to the enclosing element for its x:Key.
        foreach (Match m in BrushColorRegex.Matches(colorsText))
        {
            var hex = m.Groups[1].Value;
            var rgb = ParseHex(hex);
            if (!rgb.HasValue) continue;
            var element = GetEnclosingElement(colorsText, m.Index);
            var km = BrushKeyRegex.Match(element);
            if (!km.Success) continue;
            var name = km.Groups[1].Value;
            if (!palette.ContainsKey(name))
                palette[name] = rgb.Value;
        }

        Assert.True(palette.Count > 0,
            "No color resources found in Theme/Colors.axaml.");

        // ── Font-size floor: no token below 12 ──────────────────────────
        var typographyText = File.ReadAllText(typographyPath);
        var fontSizeTokens = new Dictionary<string, double>(StringComparer.Ordinal);
        foreach (Match m in FontSizeRegex.Matches(typographyText))
        {
            var name = m.Groups[1].Value;
            var value = double.Parse(m.Groups[2].Value, CultureInfo.InvariantCulture);
            fontSizeTokens[name] = value;
        }

        Assert.True(fontSizeTokens.Count > 0,
            "No font-size tokens found in Theme/Typography.axaml.");

        var tooSmall = new List<string>();
        foreach (var (name, value) in fontSizeTokens.OrderBy(kv => kv.Value))
        {
            if (value < 12.0)
                tooSmall.Add($"  {name} = {value}px (minimum is 12px)");
        }

        Assert.True(tooSmall.Count == 0,
            $"Found {tooSmall.Count} font-size token(s) below the 12px floor:\n"
            + string.Join("\n", tooSmall));

        // ── Contrast pairings ───────────────────────────────────────────
        var failures = new List<string>();

        void CheckPair(string fgName, string bgName, double threshold, string label)
        {
            if (!palette.TryGetValue(fgName, out var fg))
            { failures.Add($"  Missing foreground token: {fgName}"); return; }
            if (!palette.TryGetValue(bgName, out var bg))
            { failures.Add($"  Missing background token: {bgName}"); return; }
            var ratio = DesignTokenAccessibilityTests.ContrastRatio(
                fg.r, fg.g, fg.b, bg.r, bg.g, bg.b);
            if (ratio < threshold)
                failures.Add($"  {label}: {fgName} on {bgName} = {ratio:F2}:1 (need ≥ {threshold}:1)");
        }

        var AA = DesignTokenAccessibilityTests.AaNormalText;
        var AAui = DesignTokenAccessibilityTests.AaLargeText;

        // Normal-text pairings (4.5:1)
        CheckPair("TextPrimaryBrush", "PanelBgBrush", AA, "Primary text on panel");
        CheckPair("TextPrimaryBrush", "SurfaceBrush", AA, "Primary text on surface");
        CheckPair("TextPrimaryBrush", "CardBgBrush", AA, "Primary text on card");
        CheckPair("TextHeadingBrush", "PanelBgBrush", AA, "Heading text on panel");
        CheckPair("TextSubtleBrush", "PanelBgBrush", AA, "Subtle text on panel");
        CheckPair("TextMutedBrush", "PanelBgBrush", AA, "Muted text on panel");
        CheckPair("TextPrimaryBrush", "WindowBgBrush", AA, "Primary text on window");

        // Large-text / UI pairings (3:1)
        CheckPair("AccentBrush", "SurfaceBrush", AAui, "Accent on surface");
        CheckPair("AccentBrush", "FocusToggleBgBrush", AAui, "Focus-toggle fg on bg");
        CheckPair("FocusToggleTextBrush", "FocusToggleBgBrush", AAui, "Focus-toggle text on bg");
        CheckPair("WarningBrush", "WarningBgBrush", AAui, "Warning on warning bg");
        CheckPair("SelectionBrush", "SelectedBgBrush", AAui, "Selection on selected bg");
        CheckPair("ErrorBrush", "ErrorBgBrush", AAui, "Error on error bg");
        CheckPair("SelectionBrush", "CardBgBrush", AAui, "Selection border on card");

        Assert.True(failures.Count == 0,
            $"Found {failures.Count} accessibility violation(s) in design tokens:\n"
            + string.Join("\n", failures));
    }
}

